        print(f"\n[{name}]")

        # Download the WAV file
        wav_bytes = download_wav(url, name)

        if wav_bytes and len(wav_bytes) > 100:
            # Save to temp file for reference
            temp_path = save_wav_temp(wav_bytes, name)
            if temp_path:
                print(f"  Saved to: {temp_path}")

            # Read WAV data
            audio_data, sample_rate = read_wav_from_bytes(wav_bytes)

            if audio_data is not None and sample_rate is not None:
                play_audio(audio_data, sample_rate, name)
                played_count += 1

                # Clean up temp file
                if temp_path and os.path.exists(temp_path):
                    os.unlink(temp_path)
            else:
                print(f"  Could not decode WAV data for: {name}")
                failed_downloads.append(name)
        else:
            print(f"  Download failed or empty response for: {name}")
